import{_ as e,o as s,c as i,ay as l}from"./chunks/framework.-lzFfN-z.js";const p=JSON.parse('{"title":"CSS 单位 (Units)","description":"","frontmatter":{},"headers":[],"relativePath":"css/units.md","filePath":"css/units.md","lastUpdated":1772787829000}'),a={name:"css/units.md"};function n(d,t,o,h,r,g){return s(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="css-单位-units" tabindex="-1">CSS 单位 (Units) <a class="header-anchor" href="#css-单位-units" aria-label="Permalink to &quot;CSS 单位 (Units)&quot;">​</a></h1><p>CSS 单位是布局的标尺。选对单位，能让你的布局自动适应各种屏幕，极大减少 Media Query 的代码量。</p><h2 id="_1-绝对长度单位-absolute-lengths" tabindex="-1">1. 绝对长度单位 (Absolute Lengths) <a class="header-anchor" href="#_1-绝对长度单位-absolute-lengths" aria-label="Permalink to &quot;1. 绝对长度单位 (Absolute Lengths)&quot;">​</a></h2><p>这类单位与屏幕物理尺寸挂钩，不随容器或字体变化。</p><table tabindex="0"><thead><tr><th style="text-align:left;">单位</th><th style="text-align:left;">描述</th><th style="text-align:left;">换算关系 (基准)</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>px</code></strong></td><td style="text-align:left;"><strong>像素</strong></td><td style="text-align:left;">1px = 1/96 英寸</td><td style="text-align:left;"><strong>边框 (<code>border</code>)、阴影、极其精细的定位</strong>。在屏幕上它是逻辑像素，不是物理像素。</td></tr><tr><td style="text-align:left;"><code>cm</code> / <code>mm</code></td><td style="text-align:left;">厘米 / 毫米</td><td style="text-align:left;">1cm = 37.8px</td><td style="text-align:left;"><strong>打印样式表</strong> (<code>@media print</code>)。在屏幕上不准确。</td></tr><tr><td style="text-align:left;"><code>in</code></td><td style="text-align:left;">英寸</td><td style="text-align:left;">1in = 96px</td><td style="text-align:left;">打印。</td></tr><tr><td style="text-align:left;"><code>pt</code></td><td style="text-align:left;">点 (Point)</td><td style="text-align:left;">1pt = 1/72 英寸</td><td style="text-align:left;">打印、Word 文档排版习惯。</td></tr></tbody></table><h2 id="_2-相对长度单位-relative-lengths" tabindex="-1">2. 相对长度单位 (Relative Lengths) <a class="header-anchor" href="#_2-相对长度单位-relative-lengths" aria-label="Permalink to &quot;2. 相对长度单位 (Relative Lengths)&quot;">​</a></h2><p>这类单位是响应式设计的基石。</p><h3 id="_2-1-字体相对单位-font-relative" tabindex="-1">2.1 字体相对单位 (Font-relative) <a class="header-anchor" href="#_2-1-字体相对单位-font-relative" aria-label="Permalink to &quot;2.1 字体相对单位 (Font-relative)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">单位</th><th style="text-align:left;">基准 (Relative to)</th><th style="text-align:left;">核心特性</th><th style="text-align:left;">最佳实践</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>em</code></strong></td><td style="text-align:left;"><strong>父元素</strong>的字号</td><td style="text-align:left;"><strong>继承性</strong>。多层嵌套会累乘 (1.2 * 1.2 * 1.2)。</td><td style="text-align:left;">用于组件内部的 <strong>Padding / Margin / Radius</strong>。当组件字号变大，间距自动变大。</td></tr><tr><td style="text-align:left;"><strong><code>rem</code></strong></td><td style="text-align:left;"><strong>根元素 (<code>html</code>)</strong> 的字号</td><td style="text-align:left;"><strong>稳定性</strong>。全页面统一基准，无复利计算。</td><td style="text-align:left;">用于 <strong>Font-size</strong> 和整体布局间距。</td></tr><tr><td style="text-align:left;"><strong><code>ch</code></strong></td><td style="text-align:left;">字符 <code>0</code> 的宽度</td><td style="text-align:left;">约等于半角字符宽。</td><td style="text-align:left;"><strong>限制文本阅读宽度</strong> (<code>max-width: 65ch</code>)。</td></tr><tr><td style="text-align:left;"><code>ex</code></td><td style="text-align:left;">字符 <code>x</code> 的高度</td><td style="text-align:left;">约等于 0.5em。</td><td style="text-align:left;">垂直对齐微调。</td></tr><tr><td style="text-align:left;"><code>lh</code> (新)</td><td style="text-align:left;">当前元素的行高</td><td style="text-align:left;"><code>line-height</code>。</td><td style="text-align:left;">绘制与行高对齐的背景色块。</td></tr><tr><td style="text-align:left;"><code>ic</code> (新)</td><td style="text-align:left;">字符 <code>水</code> 的宽度</td><td style="text-align:left;">CJK (中日韩) 文字宽度。</td><td style="text-align:left;">控制中文排版宽度。</td></tr></tbody></table><h3 id="_2-2-视口相对单位-viewport-relative-v1-0" tabindex="-1">2.2 视口相对单位 (Viewport-relative) v1.0 <a class="header-anchor" href="#_2-2-视口相对单位-viewport-relative-v1-0" aria-label="Permalink to &quot;2.2 视口相对单位 (Viewport-relative) v1.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">单位</th><th style="text-align:left;">基准</th><th style="text-align:left;">描述</th><th style="text-align:left;">常见坑点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>vw</code></strong></td><td style="text-align:left;">视口宽度的 1%</td><td style="text-align:left;">包含滚动条宽度。</td><td style="text-align:left;"><code>100vw</code> 可能会导致横向滚动条。</td></tr><tr><td style="text-align:left;"><strong><code>vh</code></strong></td><td style="text-align:left;">视口高度的 1%</td><td style="text-align:left;"></td><td style="text-align:left;">在移动端，地址栏收缩会导致 <code>100vh</code> 高度跳变或遮挡。</td></tr><tr><td style="text-align:left;"><code>vmin</code></td><td style="text-align:left;"><code>min(vw, vh)</code></td><td style="text-align:left;">选取宽高中较小的一边。</td><td style="text-align:left;">保证物体在横竖屏下都能完整显示在屏幕内。</td></tr><tr><td style="text-align:left;"><code>vmax</code></td><td style="text-align:left;"><code>max(vw, vh)</code></td><td style="text-align:left;">选取宽高中较大的一边。</td><td style="text-align:left;">全屏大背景。</td></tr></tbody></table><h3 id="_2-3-视口相对单位-viewport-v2-0-——-解决移动端痛点" tabindex="-1">2.3 视口相对单位 (Viewport) v2.0 —— <strong>解决移动端痛点</strong> <a class="header-anchor" href="#_2-3-视口相对单位-viewport-v2-0-——-解决移动端痛点" aria-label="Permalink to &quot;2.3 视口相对单位 (Viewport) v2.0 —— **解决移动端痛点**&quot;">​</a></h3><p><em>(现代浏览器 Chrome 108+, Safari 15.4+ 支持)</em></p><table tabindex="0"><thead><tr><th style="text-align:left;">单位</th><th style="text-align:left;">全称</th><th style="text-align:left;">解决的问题</th><th style="text-align:left;">推荐场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>svh</code></strong></td><td style="text-align:left;"><strong>Small</strong> Viewport Height</td><td style="text-align:left;">移动端地址栏<strong>展开</strong>时（可视区域最小）的高度。</td><td style="text-align:left;"><strong>底部按钮、Tab栏</strong>。防止被地址栏遮挡。</td></tr><tr><td style="text-align:left;"><strong><code>lvh</code></strong></td><td style="text-align:left;"><strong>Large</strong> Viewport Height</td><td style="text-align:left;">移动端地址栏<strong>收起</strong>时（可视区域最大）的高度。</td><td style="text-align:left;">全屏沉浸式背景图。</td></tr><tr><td style="text-align:left;"><strong><code>dvh</code></strong></td><td style="text-align:left;"><strong>Dynamic</strong> Viewport Height</td><td style="text-align:left;">随地址栏伸缩<strong>实时变化</strong>。</td><td style="text-align:left;">追求完美贴合，但拖动时会触发重排，有性能损耗。</td></tr><tr><td style="text-align:left;"><code>svw</code>, <code>lvw</code>, <code>dvw</code></td><td style="text-align:left;">对应的宽度单位</td><td style="text-align:left;">(通常宽度不变，用的少)</td><td style="text-align:left;">-</td></tr></tbody></table><h2 id="_3-容器查询单位-container-query-units" tabindex="-1">3. 容器查询单位 (Container Query Units) <a class="header-anchor" href="#_3-容器查询单位-container-query-units" aria-label="Permalink to &quot;3. 容器查询单位 (Container Query Units)&quot;">​</a></h2><p><em>(需要配合 <code>container-type</code> 使用)</em></p><table tabindex="0"><thead><tr><th style="text-align:left;">单位</th><th style="text-align:left;">描述</th><th style="text-align:left;">革命性意义</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>cqw</code></strong></td><td style="text-align:left;">查询容器宽度的 1%</td><td style="text-align:left;"><strong>组件级响应式</strong>。</td></tr><tr><td style="text-align:left;"><code>cqh</code></td><td style="text-align:left;">查询容器高度的 1%</td><td style="text-align:left;">让组件根据自己所在的“坑位”大小自动调整字号，而不是根据屏幕大小。</td></tr><tr><td style="text-align:left;"><code>cqi</code></td><td style="text-align:left;">行内方向尺寸 (Inline Size)</td><td style="text-align:left;">通常等同于宽度。</td></tr><tr><td style="text-align:left;"><code>cqb</code></td><td style="text-align:left;">块轴方向尺寸 (Block Size)</td><td style="text-align:left;">通常等同于高度。</td></tr></tbody></table><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  container-type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: inline-size;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.card</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> h2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">cqi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 标题字号永远是卡片宽度的 5% */</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="_4-角度与时间单位-其他" tabindex="-1">4. 角度与时间单位 (其他) <a class="header-anchor" href="#_4-角度与时间单位-其他" aria-label="Permalink to &quot;4. 角度与时间单位 (其他)&quot;">​</a></h2><ul><li><strong>角度</strong>: <code>deg</code> (度), <code>rad</code> (弧度), <code>turn</code> (圈, <code>1turn = 360deg</code>).</li><li><strong>时间</strong>: <code>s</code> (秒), <code>ms</code> (毫秒).</li><li><strong>分辨率</strong>: <code>dpi</code>, <code>dppx</code> (dots per pixel unit).</li></ul><h2 id="_5-常见问题-faq-与-避坑指南" tabindex="-1">5. 常见问题 (FAQ) 与 避坑指南 <a class="header-anchor" href="#_5-常见问题-faq-与-避坑指南" aria-label="Permalink to &quot;5. 常见问题 (FAQ) 与 避坑指南&quot;">​</a></h2><h3 id="_5-1-移动端-100vh-被地址栏遮挡怎么办" tabindex="-1">5.1 移动端 <code>100vh</code> 被地址栏遮挡怎么办？ <a class="header-anchor" href="#_5-1-移动端-100vh-被地址栏遮挡怎么办" aria-label="Permalink to &quot;5.1 移动端 `100vh` 被地址栏遮挡怎么办？&quot;">​</a></h3><p><strong>现象</strong>: 在 iOS Safari 或 Chrome 上，设置 <code>height: 100vh</code> 的底部按钮，被浏览器的底部工具栏盖住了。</p><p><strong>解法</strong>:</p><ol><li><strong>最佳</strong>: 使用新单位 <code>height: 100svh;</code> (Small Viewport)。</li><li><strong>兼容</strong>:<div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">height: 100vh; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 旧浏览器兜底 */</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">height: 100svh; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 新浏览器生效 */</span></span></code></pre></div></li></ol><h3 id="_5-2-为什么-width-100vw-会出现水平滚动条" tabindex="-1">5.2 为什么 <code>width: 100vw</code> 会出现水平滚动条？ <a class="header-anchor" href="#_5-2-为什么-width-100vw-会出现水平滚动条" aria-label="Permalink to &quot;5.2 为什么 `width: 100vw` 会出现水平滚动条？&quot;">​</a></h3><p><strong>原因</strong>:</p><ul><li><code>100%</code>: 占据父容器宽度（不含父容器边框，不含滚动条）。</li><li><code>100vw</code>: 占据整个视口宽度（<strong>包含</strong>垂直滚动条的宽度，通常约 15-17px）。</li><li>当页面内容过长出现垂直滚动条时，<code>100vw</code> &gt; <code>&lt;body&gt; width</code>，导致水平溢出。</li></ul><p><strong>建议</strong>: 布局宽度尽量用 <code>width: 100%</code> 或 <code>auto</code>，除非你需要通过 <code>calc(50vw - 50%)</code> 做全屏突破布局。</p><h3 id="_5-3-rem-应该设为多少-px-方便计算" tabindex="-1">5.3 <code>rem</code> 应该设为多少 px 方便计算？ <a class="header-anchor" href="#_5-3-rem-应该设为多少-px-方便计算" aria-label="Permalink to &quot;5.3 `rem` 应该设为多少 px 方便计算？&quot;">​</a></h3><p><strong>技巧</strong>: 浏览器默认字号是 16px。 为了方便计算（比如想要 14px，不想算 14/16=0.875），很多人会把根字号设为 <code>62.5%</code>。</p><ul><li><code>16px * 62.5% = 10px</code>。</li><li>此时 <code>1rem = 10px</code>。</li><li>想要 14px -&gt; 写 <code>1.4rem</code>；想要 20px -&gt; 写 <code>2.0rem</code>。</li></ul><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">62.5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">body</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.6</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">rem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 恢复回 16px */</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><h3 id="_5-4-为什么-0-不需要单位-但-0-需要" tabindex="-1">5.4 为什么 <code>0</code> 不需要单位，但 <code>0%</code> 需要？ <a class="header-anchor" href="#_5-4-为什么-0-不需要单位-但-0-需要" aria-label="Permalink to &quot;5.4 为什么 `0` 不需要单位，但 `0%` 需要？&quot;">​</a></h3><ul><li><strong>长度 (<code>length</code>)</strong>: <code>0</code> 等于 <code>0px</code> 等于 <code>0cm</code>。长度为 0 时单位可省。</li><li><strong>百分比 (<code>percentage</code>)</strong>: 不是长度单位，是比例。虽然在很多属性（如 <code>width</code>）中 <code>0</code> 和 <code>0%</code> 效果一样，但在 <code>hsl(0, 0%, 0%)</code> (颜色) 或 <code>transition-duration</code> (时间) 中，单位往往不能乱省或混用。</li><li><strong>建议</strong>: 长度值为 0 时，省略单位 (<code>margin: 0;</code>)；涉及动画时间或百分比时，保留单位。</li></ul><h3 id="_5-5-什么时候用-px-什么时候用-rem" tabindex="-1">5.5 什么时候用 <code>px</code>，什么时候用 <code>rem</code>？ <a class="header-anchor" href="#_5-5-什么时候用-px-什么时候用-rem" aria-label="Permalink to &quot;5.5 什么时候用 `px`，什么时候用 `rem`？&quot;">​</a></h3><ul><li><strong><code>rem</code></strong>: 所有的 <strong>字号 (<code>font-size</code>)</strong>、<strong>大间距 (<code>margin/padding</code>)</strong>、<strong>容器宽度</strong>。这样用户在浏览器调整“默认字号”时，整个页面会整体缩放，无障碍体验好。</li><li><strong><code>px</code></strong>: <strong>边框 (<code>border</code>)</strong>（1px 边框变粗很难看）、<strong>阴影</strong>、<strong>小圆角</strong>、<strong>背景图定位</strong>。这些通常不需要随文字缩放。</li></ul><h3 id="_5-6-怎么做等比例缩放的盒子-宽-高-16-9" tabindex="-1">5.6 怎么做等比例缩放的盒子（宽:高 = 16:9）？ <a class="header-anchor" href="#_5-6-怎么做等比例缩放的盒子-宽-高-16-9" aria-label="Permalink to &quot;5.6 怎么做等比例缩放的盒子（宽:高 = 16:9）？&quot;">​</a></h3><p><strong>旧方案</strong>: <code>padding-top</code> 百分比大法。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  padding-top</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">56.25</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 9 / 16 = 0.5625 */</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>新方案</strong>: <code>aspect-ratio</code> 属性。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  aspect-ratio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> / </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 直接写比例，现代浏览器全支持 */</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div>',42)])])}const k=e(a,[["render",n]]);export{p as __pageData,k as default};
